84	// RunFunc executes a single agent invocation and returns the Result. Used by
85	// the comparison helpers so the same orchestration logic can be driven by
86	// either the legacy Runner or the agent service.
87	type RunFunc func(opts RunOptions) (*Result, error)
88	
89	// RunCompareWith dispatches the same prompt to multiple harnesses, executing
90	// each arm via run, and returns a ComparisonRecord. Production callers should
91	// use RunCompareViaService; tests may pass Runner.Run as the closure.
92	func RunCompareWith(run RunFunc, opts CompareOptions, resolvePrompt func(RunOptions) (string, error), cleanupSandbox func(repoDir, compareID string)) (*ComparisonRecord, error) {
93		if len(opts.Harnesses) == 0 {
94			return nil, fmt.Errorf("agent: compare requires at least one harness")
95		}
96		if resolvePrompt == nil {
97			resolvePrompt = defaultResolvePromptForCompare
98		}
99	
100		prompt, err := resolvePrompt(opts.RunOptions)
101		if err != nil {
102			return nil, err
103		}
104	
105		id := genCompareID()
106		record := &ComparisonRecord{
107			ID:        id,
108			Timestamp: time.Now().UTC(),
109			Prompt:    prompt,
110			Arms:      make([]ComparisonArm, len(opts.Harnesses)),
111		}
112	
113		baseDir := opts.WorkDir
114		if baseDir == "" {
115			baseDir, _ = os.Getwd()
116		}
117	
118		worktrees := make([]string, len(opts.Harnesses))
119		if opts.Sandbox {
120			for i, harness := range opts.Harnesses {
121				label := harness
122				if l, ok := opts.ArmLabels[i]; ok {
123					label = l
124				}
125				wt, err := createCompareWorktree(baseDir, id, label)
126				if err != nil {
127					record.Arms[i] = ComparisonArm{
128						Harness:  label,
129						ExitCode: 1,
130						Error:    fmt.Sprintf("worktree: %s", err),
131					}
132					continue
133				}
134				worktrees[i] = wt
135			}
136		}
137	
138		var wg sync.WaitGroup
139		for i, harness := range opts.Harnesses {
140			if opts.Sandbox && worktrees[i] == "" && record.Arms[i].Error != "" {
141				continue
142			}
143			wg.Add(1)
144			go func(idx int, harnessName string) {
145				defer wg.Done()
146				record.Arms[idx] = runCompareArmWith(run, opts, idx, harnessName, baseDir, prompt, worktrees[idx])
147			}(i, harness)
148		}
149		wg.Wait()
150	
151		if opts.Sandbox && !opts.KeepSandbox {
152			if cleanupSandbox != nil {
153				cleanupSandbox(baseDir, id)
154			} else {
155				cleanupCompareWorktrees(baseDir, id)
156			}
157		}
158	
159		return record, nil
160	}
