181	// defaultResolvePromptForCompare reads inline Prompt or PromptFile.
182	func defaultResolvePromptForCompare(opts RunOptions) (string, error) {
183		prompt := opts.Prompt
184		if opts.PromptFile != "" {
185			data, err := readPromptFileBounded(opts.PromptFile)
186			if err != nil {
187				return "", fmt.Errorf("agent: read prompt file: %w", err)
188			}
189			prompt = string(data)
190		}
191		if prompt == "" {
192			return "", fmt.Errorf("agent: prompt is required")
193		}
194		return prompt, nil
195	}
