197	func runCompareArmWith(run RunFunc, opts CompareOptions, armIdx int, harnessName, baseDir, prompt, worktreePath string) ComparisonArm {
198		label := harnessName
199		if l, ok := opts.ArmLabels[armIdx]; ok {
200			label = l
201		}
202		arm := ComparisonArm{Harness: label}
203	
204		workDir := baseDir
205		if worktreePath != "" {
206			workDir = worktreePath
207		}
208	
209		model := opts.Model
210		if m, ok := opts.ArmModels[armIdx]; ok {
211			model = m
212		}
213	
214		runOpts := RunOptions{
215			Harness:     harnessName,
216			Prompt:      prompt,
217			Model:       model,
218			Effort:      opts.Effort,
219			Timeout:     opts.Timeout,
220			WorkDir:     workDir,
221			Permissions: opts.Permissions,
222			Correlation: opts.Correlation,
223		}
224	
225		result, err := run(runOpts)
226		if err != nil {
227			arm.ExitCode = 1
228			arm.Error = err.Error()
229		} else {
230			arm.Model = result.Model
231			arm.Output = result.Output
232			arm.ToolCalls = result.ToolCalls
233			arm.Tokens = result.Tokens
234			arm.InputTokens = result.InputTokens
235			arm.OutputTokens = result.OutputTokens
236			arm.CostUSD = result.CostUSD
237			arm.DurationMS = result.DurationMS
238			arm.ExitCode = result.ExitCode
239			arm.Error = result.Error
240		}
241	
