399	// QuorumMet returns true if enough results succeeded.
400	func QuorumMet(strategy string, threshold int, results []*Result) bool {
401		total := len(results)
402		eff := effectiveThreshold(strategy, threshold, total)
403		successes := 0
404		for _, r := range results {
405			if r != nil && r.ExitCode == 0 {
406				successes++
407			}
408		}
409		return successes >= eff
410	}
