412	func effectiveThreshold(strategy string, threshold, total int) int {
413		switch strategy {
414		case "any":
415			return 1
416		case "majority":
417			return (total / 2) + 1
418		case "unanimous":
419			return total
420		default:
421			if threshold > 0 {
422				return threshold
423			}
424			return 1
425		}
426	}
