625	func benchSummarize(result *BenchmarkResult) BenchmarkSummary {
626		summary := BenchmarkSummary{
627			TotalPrompts: len(result.Comparisons),
628		}
629		armStats := make(map[string]*BenchmarkArmSummary)
630		armOrder := make([]string, len(result.Arms))
631		for i, arm := range result.Arms {
632			label := arm.Label
633			armOrder[i] = label
634			armStats[label] = &BenchmarkArmSummary{Label: label}
635		}
636		for _, cmp := range result.Comparisons {
637			for _, arm := range cmp.Arms {
638				stats, ok := armStats[arm.Harness]
639				if !ok {
640					continue
641				}
642				if arm.ExitCode == 0 {
643					stats.Completed++
644				} else {
645					stats.Failed++
646				}
647				stats.TotalTokens += arm.Tokens
648				stats.TotalCostUSD += arm.CostUSD
649				stats.AvgDurationMS += arm.DurationMS
650			}
651		}
652		for _, label := range armOrder {
653			stats := armStats[label]
654			total := stats.Completed + stats.Failed
655			if total > 0 {
656				stats.AvgDurationMS = stats.AvgDurationMS / total
657			}
658			summary.Arms = append(summary.Arms, *stats)
659		}
660		return summary
661	}
